import { cn } from "@/lib/utils"

import type { CalendarClassNames, CalendarSlot } from "./types"

export function getCalendarSlotClassName(
  classNames: CalendarClassNames | undefined,
  slot: CalendarSlot,
  ...values: Array<string | undefined>
) {
  return cn(values, classNames?.[slot])
}

export * from "./internal/utils/calendar/date-range"
export * from "./internal/utils/calendar/formatting"
export * from "./internal/utils/calendar/occurrences"
export * from "./internal/utils/calendar/operations"
export * from "./internal/utils/calendar/permissions"
export * from "./internal/utils/calendar/ics"

import * as React from "react"

import type { CalendarEvent } from "../../types"
import {
  getCalendarSlotClassName,
  intervalOverlapsBlockedRanges,
  normalizeAvailableViews,
  normalizeHiddenDays,
  resolveCalendarView,
} from "../../utils"
import { CalendarAgendaView } from "./agenda-view"
import { CalendarMonthView } from "./month-view"
import { CalendarToolbar } from "./toolbar"
import { CalendarDayView, CalendarWeekView } from "./time-grid-view"
import {
  compactSlotHeight,
  defaultMaxHour,
  defaultMinHour,
  defaultSlotDuration,
  slotHeight as defaultSlotHeight,
  type CalendarRootProps,
} from "../shared"
import { CalendarRootPortals } from "./root/calendar/portals"
import { getCalendarSurfaceShadowClassName } from "./root/root-utils"
import { useCalendarDerivedState } from "./root/use-calendar-derived-state"
import { useCalendarEventActions } from "./root/use-calendar-event-actions"
import { useCalendarPointerInteractions } from "./root/use-calendar-pointer-interactions"

export function CalendarRoot({
  agendaDays = 14,
  availableViews,
  blockedRanges,
  businessHours,
  classNames,
  createEventSheet,
  date,
  density = "comfortable",
  eventChangeConfirmation,
  eventDetails,
  events,
  getEventColor,
  hiddenDays,
  hourCycle,
  keyboardShortcuts,
  locale,
  maxHour = defaultMaxHour,
  minHour = defaultMinHour,
  onDateChange,
  onEventArchive,
  onEventCreate,
  onEventDelete,
  onEventDuplicate,
  onEventMove,
  onEventResize,
  onEventSelect,
  onEventUpdate,
  onNavigate,
  onResourceFilterChange,
  onSelectedEventChange,
  onToday,
  onViewChange,
  renderEmptyState,
  renderEvent,
  renderEventDetails,
  renderToolbarExtras,
  resources,
  resourceFilter,
  scrollToTime,
  secondaryTimeZone,
  selectedEventId,
  showCreatePreviewMeta = true,
  showDragPreviewMeta = true,
  showSecondaryTimeZone = false,
  slotDuration = defaultSlotDuration,
  slotHeight: customSlotHeight,
  surfaceShadow = "none",
  defaultResourceFilter,
  timeZone,
  view,
  weekStartsOn = 1,
}: CalendarRootProps) {
  const [optimisticEvents, setOptimisticEvents] =
    React.useState<CalendarEvent[]>(events)
  const [isHydrated, setIsHydrated] = React.useState(false)
  const allResourceIds = React.useMemo(
    () => resources?.map((resource) => resource.id) ?? [],
    [resources]
  )
  const [internalResourceFilter, setInternalResourceFilter] = React.useState<
    string[]
  >(() => defaultResourceFilter ?? allResourceIds)
  const resolvedAvailableViews = React.useMemo(
    () => normalizeAvailableViews(availableViews),
    [availableViews]
  )
  const resolvedHiddenDays = React.useMemo(
    () => normalizeHiddenDays(hiddenDays),
    [hiddenDays]
  )
  const resolvedView = React.useMemo(
    () => resolveCalendarView(view, resolvedAvailableViews),
    [resolvedAvailableViews, view]
  )
  const resolvedSlotHeight =
    customSlotHeight ??
    (density === "compact" ? compactSlotHeight : defaultSlotHeight)
  const resolvedResourceFilter = React.useMemo(() => {
    const nextFilter = resourceFilter ?? internalResourceFilter
    const dedupedFilter = Array.from(new Set(nextFilter)).filter((id) =>
      allResourceIds.includes(id)
    )

    if (allResourceIds.length === 0) {
      return dedupedFilter
    }

    return dedupedFilter.length > 0 ? dedupedFilter : allResourceIds
  }, [allResourceIds, internalResourceFilter, resourceFilter])

  React.useEffect(() => {
    setIsHydrated(true)
  }, [])

  React.useLayoutEffect(() => {
    setOptimisticEvents(events)
  }, [events])

  React.useEffect(() => {
    setInternalResourceFilter((currentFilter) => {
      if (resourceFilter) {
        return currentFilter
      }

      const nextFilter =
        currentFilter.length > 0
          ? currentFilter.filter((id) => allResourceIds.includes(id))
          : defaultResourceFilter ?? allResourceIds

      return nextFilter.length > 0 || allResourceIds.length === 0
        ? nextFilter
        : allResourceIds
    })
  }, [allResourceIds, defaultResourceFilter, resourceFilter])

  const setActiveResourceIds = React.useCallback(
    (nextResourceIds: string[]) => {
      const dedupedResourceIds = Array.from(new Set(nextResourceIds)).filter((id) =>
        allResourceIds.includes(id)
      )

      if (!resourceFilter) {
        setInternalResourceFilter(dedupedResourceIds)
      }

      onResourceFilterChange?.(dedupedResourceIds)
    },
    [allResourceIds, onResourceFilterChange, resourceFilter]
  )

  const shouldBlockTimedRange = React.useCallback(
    (start: Date, end: Date, allDay: boolean | undefined) => {
      if (
        allDay ||
        resolvedView === "month" ||
        resolvedView === "agenda" ||
        !blockedRanges?.length
      ) {
        return false
      }

      return intervalOverlapsBlockedRanges(start, end, blockedRanges)
    },
    [blockedRanges, resolvedView]
  )

  const actions = useCalendarEventActions({
    createEventSheet,
    date,
    eventChangeConfirmation,
    eventDetails,
    hourCycle,
    isHydrated,
    keyboardShortcuts,
    locale,
    minHour,
    onDateChange,
    onEventArchive,
    onEventCreate,
    onEventDelete,
    onEventDuplicate,
    onEventMove,
    onEventResize,
    onEventSelect,
    onEventUpdate,
    onNavigate,
    onSelectedEventChange,
    onToday,
    optimisticEvents,
    resolvedHiddenDays,
    resolvedResourceFilter,
    resolvedView,
    resources,
    setOptimisticEvents,
    shouldBlockTimedRange,
    slotDuration,
    timeZone,
  })

  const pointer = useCalendarPointerInteractions({
    announce: actions.announce,
    closeContextMenu: actions.closeContextMenu,
    closeEventDetails: actions.closeEventDetails,
    enableEventMove: !!onEventMove,
    enableEventResize: !!onEventResize,
    moveOccurrenceWithTarget: actions.moveOccurrenceWithTarget,
    resizeOccurrenceWithTarget: actions.resizeOccurrenceWithTarget,
    selectOccurrence: (occurrence) => {
      actions.handleSelectEvent(occurrence)
    },
  })

  const derived = useCalendarDerivedState({
    activeDrag: pointer.activeDrag,
    activeDragOffsetMinutes: pointer.activeDragOffsetMinutes,
    activeDropTarget: pointer.activeDropTarget,
    activeResize: pointer.activeResize,
    activeResizeTarget: pointer.activeResizeTarget,
    agendaDays,
    blockedRanges,
    businessHours,
    classNames,
    clearResourceFilter: () => setActiveResourceIds(allResourceIds),
    date,
    density,
    getEventColor,
    handleEventCreateRequest: onEventCreate
      ? actions.requestEventCreate
      : undefined,
    handleEventDragPointerDown: pointer.handleEventDragPointerDown,
    handleEventKeyCommand: actions.handleEventKeyCommand,
    handleOpenContextMenu: actions.handleOpenContextMenu,
    handleResizeHandlePointerDown: pointer.handleResizeHandlePointerDown,
    handleSelectEvent: (occurrence) => {
      actions.handleSelectEvent(occurrence)
    },
    hourCycle,
    isHydrated,
    isPointerDragging: pointer.isPointerDragging,
    locale,
    optimisticEvents,
    renderEmptyState,
    renderEvent,
    resolvedHiddenDays,
    resolvedResourceFilter,
    resolvedSlotHeight,
    resolvedView,
    resources,
    scrollToTime,
    secondaryTimeZone,
    selectedEventId,
    shouldBlockTimedRange,
    shouldSuppressEventClick: pointer.shouldSuppressEventClick,
    showCreatePreviewMeta,
    showDragPreviewMeta,
    showSecondaryTimeZone,
    slotDuration,
    timeZone,
    weekStartsOn,
  })
  const detailsOccurrence = actions.detailsOccurrence
  const setDetailsOccurrence = actions.setDetailsOccurrence

  React.useEffect(() => {
    if (
      selectedEventId &&
      !derived.occurrences.some(
        (occurrence) => occurrence.occurrenceId === selectedEventId
      )
    ) {
      onSelectedEventChange?.(undefined)
    }

    if (
      detailsOccurrence &&
      !derived.occurrences.some(
        (occurrence) => occurrence.occurrenceId === detailsOccurrence.occurrenceId
      )
    ) {
      setDetailsOccurrence(null)
    }
  }, [
    detailsOccurrence,
    derived.occurrences,
    onSelectedEventChange,
    setDetailsOccurrence,
    selectedEventId,
  ])

  return (
    <div
      className={getCalendarSlotClassName(
        classNames,
        "root",
        "flex min-h-[42rem] flex-col overflow-hidden rounded-[calc(var(--radius)*1.6)] border border-border/70 bg-background",
        getCalendarSurfaceShadowClassName(surfaceShadow)
      )}
      data-testid="calendar-root"
    >
      <CalendarToolbar
        activeResourceIds={resolvedResourceFilter}
        availableViews={resolvedAvailableViews}
        classNames={classNames}
        currentLabel={derived.currentLabel}
        density={density}
        onNavigate={actions.handleNavigate}
        onQuickCreate={onEventCreate ? actions.handleQuickCreate : undefined}
        onResourceFilterChange={
          resources?.length && resources.length > 1 ? setActiveResourceIds : undefined
        }
        onToday={actions.handleToday}
        onViewChange={onViewChange}
        renderToolbarExtras={renderToolbarExtras}
        resources={resources}
        secondaryTimeZone={secondaryTimeZone}
        showSecondaryTimeZone={showSecondaryTimeZone}
        timeZone={timeZone}
        view={resolvedView}
      />
      <div
        className={getCalendarSlotClassName(
          classNames,
          "shell",
          "relative flex min-h-0 flex-1 flex-col bg-background"
        )}
      >
        {resolvedView === "month" ? (
          <CalendarMonthView {...derived.sharedViewProps} />
        ) : null}
        {resolvedView === "week" ? (
          <CalendarWeekView
            {...derived.sharedViewProps}
            maxHour={maxHour}
            minHour={minHour}
          />
        ) : null}
        {resolvedView === "day" ? (
          <CalendarDayView
            {...derived.sharedViewProps}
            maxHour={maxHour}
            minHour={minHour}
          />
        ) : null}
        {resolvedView === "agenda" ? (
          <CalendarAgendaView
            {...derived.sharedViewProps}
            range={derived.range}
          />
        ) : null}
        {derived.occurrences.length === 0 ? (
          <div className="pointer-events-none absolute inset-x-4 bottom-4 z-20 flex justify-center">
            <div className="pointer-events-auto max-w-md rounded-[calc(var(--radius)*1.1)] border border-border/70 bg-background/95 px-4 py-3 text-center shadow-lg backdrop-blur-sm">
              {derived.emptyStateContent ?? (
                <>
                  <p className="font-medium">No events match this view.</p>
                  <p className="mt-1 text-sm text-muted-foreground">
                    Adjust the resource filters or create a new event to start
                    filling the schedule.
                  </p>
                </>
              )}
            </div>
          </div>
        ) : null}
      </div>
      <CalendarRootPortals
        activeDrag={pointer.activeDrag}
        activeDragInteraction={pointer.activeDragInteraction}
        activeDragRect={pointer.activeDragRect}
        classNames={classNames}
        closeContextMenu={actions.closeContextMenu}
        closeCreateSheet={actions.closeCreateSheet}
        closeEventDetails={actions.closeEventDetails}
        closePendingEventChange={actions.closePendingEventChange}
        commitCreateEvent={actions.commitCreateEvent}
        commitEventUpdate={actions.commitEventUpdate}
        contextMenu={actions.contextMenu}
        createEventSheet={createEventSheet}
        createSheetOperation={actions.createSheetOperation}
        density={density}
        detailsOccurrence={detailsOccurrence}
        eventChangeConfirmation={eventChangeConfirmation}
        eventDetails={eventDetails}
        eventDetailsEnabled={actions.eventDetailsEnabled}
        getEventColor={getEventColor}
        handleArchiveEvent={actions.handleArchiveEvent}
        handleConfirmPendingEventChange={actions.handleConfirmPendingEventChange}
        handleDeleteEvent={actions.handleDeleteEvent}
        handleDuplicateEvent={actions.handleDuplicateEvent}
        hourCycle={hourCycle}
        isHydrated={isHydrated}
        isKeyboardShortcutsOpen={actions.isKeyboardShortcutsOpen}
        isPointerDragging={pointer.isPointerDragging}
        keyboardShortcuts={keyboardShortcuts}
        locale={locale}
        onEventArchive={onEventArchive}
        onEventDelete={onEventDelete}
        onEventDuplicate={onEventDuplicate}
        onEventUpdate={onEventUpdate}
        openEventDetails={actions.openEventDetails}
        pendingEventChange={actions.pendingEventChange}
        renderEvent={renderEvent}
        renderEventDetails={renderEventDetails}
        resources={resources}
        secondaryTimeZone={secondaryTimeZone}
        setIsKeyboardShortcutsOpen={actions.setIsKeyboardShortcutsOpen}
        shouldSuppressEventClick={pointer.shouldSuppressEventClick}
        showDragPreviewMeta={showDragPreviewMeta}
        showSecondaryTimeZone={showSecondaryTimeZone}
        timeZone={timeZone}
      />
      <p
        aria-live="polite"
        className="sr-only"
        data-testid="calendar-live-announcement"
      >
        {actions.liveAnnouncement}
      </p>
    </div>
  )
}

import type { ComponentProps, ComponentType } from "react"

import {
  CaretLeftIcon,
  CaretRightIcon,
  ColumnsIcon,
  ListBulletsIcon,
  PlusIcon,
  RowsIcon,
  SquaresFourIcon,
} from "@phosphor-icons/react"

import { cn } from "@/lib/utils"

import { type CalendarView } from "../../types"
import { getCalendarSlotClassName } from "../../utils"
import type { CalendarToolbarProps } from "../shared"

const viewLabels: Record<CalendarView, string> = {
  month: "Month",
  week: "Week",
  day: "Day",
  agenda: "Agenda",
}

const viewIcons: Record<CalendarView, ComponentType<{ className?: string }>> = {
  month: SquaresFourIcon,
  week: ColumnsIcon,
  day: RowsIcon,
  agenda: ListBulletsIcon,
}

function ToolbarButton({
  className,
  size = "sm",
  tone = "ghost",
  ...props
}: ComponentProps<"button"> & {
  size?: "icon-sm" | "sm"
  tone?: "default" | "ghost" | "outline" | "secondary"
}) {
  return (
    <button
      className={cn(
        "inline-flex shrink-0 items-center justify-center rounded-[min(var(--radius-md),10px)] border text-sm font-medium whitespace-nowrap transition-colors outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/40 disabled:pointer-events-none disabled:opacity-50",
        size === "icon-sm" ? "size-8" : "h-8 gap-1 px-2.5",
        tone === "default"
          ? "border-transparent bg-primary text-primary-foreground hover:bg-primary/90"
          : "",
        tone === "ghost"
          ? "border-transparent bg-transparent hover:bg-muted hover:text-foreground"
          : "",
        tone === "outline"
          ? "border-border bg-background text-foreground shadow-xs hover:bg-muted"
          : "",
        tone === "secondary"
          ? "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80"
          : "",
        className
      )}
      type="button"
      {...props}
    />
  )
}

export function CalendarToolbar({
  activeResourceIds,
  availableViews,
  classNames,
  currentLabel,
  density = "comfortable",
  onNavigate,
  onQuickCreate,
  onResourceFilterChange,
  onToday,
  onViewChange,
  renderToolbarExtras,
  resources,
  secondaryTimeZone,
  showSecondaryTimeZone,
  timeZone,
  view,
}: CalendarToolbarProps) {
  const visibleResourceCount = activeResourceIds.length || resources?.length || 0
  const hasResourceFilters = Boolean(
    resources &&
      resources.length > 1 &&
      onResourceFilterChange
  )
  const allResourceIds = resources?.map((resource) => resource.id) ?? []
  const allResourcesSelected =
    !resources?.length ||
    activeResourceIds.length === 0 ||
    activeResourceIds.length === allResourceIds.length
  const toolbarExtras = renderToolbarExtras?.({
    activeResourceIds,
    availableViews,
    resources: resources ?? [],
    view,
  })
  const showViewSwitcher = availableViews.length > 1

  return (
    <div
      className={getCalendarSlotClassName(
        classNames,
        "toolbar",
        cn(
          "flex flex-col border-b border-border/70 md:px-5",
          density === "compact" ? "gap-3 px-4 py-3" : "gap-4 px-4 py-4"
        )
      )}
    >
      <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
        <div className="flex min-w-0 flex-wrap items-start gap-2 sm:items-center">
          <div className="flex shrink-0 items-center gap-2">
            <ToolbarButton
              aria-label="Previous range"
              data-testid="calendar-nav-previous"
              onClick={() => onNavigate(-1)}
              size="icon-sm"
              tone="ghost"
            >
              <CaretLeftIcon className="size-4" />
            </ToolbarButton>
            <ToolbarButton
              aria-label="Next range"
              data-testid="calendar-nav-next"
              onClick={() => onNavigate(1)}
              size="icon-sm"
              tone="ghost"
            >
              <CaretRightIcon className="size-4" />
            </ToolbarButton>
            <ToolbarButton
              data-testid="calendar-nav-today"
              onClick={onToday}
              size="sm"
              tone="outline"
            >
              Today
            </ToolbarButton>
          </div>
          <div className="min-w-0 basis-full pt-1 sm:ml-2 sm:basis-auto sm:pt-0">
            <p
              className={getCalendarSlotClassName(
                classNames,
                "toolbarTitle",
                "truncate text-base font-medium tracking-tight md:text-lg"
              )}
              data-testid="calendar-current-label"
            >
              {currentLabel}
            </p>
            <p className="truncate text-xs text-muted-foreground">
              {timeZone ? `${timeZone} timezone` : "Local timezone"}
              {showSecondaryTimeZone && secondaryTimeZone
                ? ` · Secondary ${secondaryTimeZone}`
                : ""}
              {resources?.length
                ? ` · ${visibleResourceCount}/${resources.length} calendars`
                : ""}
            </p>
          </div>
        </div>
        <div
          className={getCalendarSlotClassName(
            classNames,
            "toolbarGroup",
            "flex flex-wrap items-center gap-2"
          )}
        >
          {showViewSwitcher ? (
            <div
              className={getCalendarSlotClassName(
                classNames,
                "viewSwitcher",
                "grid w-full grid-cols-2 gap-1 rounded-[1.35rem] border border-border/70 bg-muted/40 p-1.5 sm:flex sm:w-auto sm:flex-wrap sm:items-center sm:gap-1 sm:rounded-full sm:p-1"
              )}
            >
              {availableViews.map((item) => {
                const Icon = viewIcons[item]

                return (
                  <ToolbarButton
                    key={item}
                    className={getCalendarSlotClassName(
                      classNames,
                      "viewButton",
                      "w-full justify-center rounded-xl sm:w-auto sm:rounded-full"
                    )}
                    data-testid={`calendar-view-${item}`}
                    onClick={() => onViewChange(item)}
                    size="sm"
                    tone={view === item ? "secondary" : "ghost"}
                  >
                    <Icon className="size-4" />
                    {viewLabels[item]}
                  </ToolbarButton>
                )
              })}
            </div>
          ) : null}
          {onQuickCreate ? (
            <ToolbarButton
              data-testid="calendar-toolbar-create"
              onClick={onQuickCreate}
              size="sm"
              tone="default"
            >
              <PlusIcon className="size-4" />
              New event
            </ToolbarButton>
          ) : null}
        </div>
      </div>
      {hasResourceFilters || toolbarExtras ? (
        <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
          {hasResourceFilters ? (
            <div className="flex flex-wrap gap-2">
              <ToolbarButton
                onClick={() => onResourceFilterChange?.(allResourceIds)}
                size="sm"
                tone={allResourcesSelected ? "secondary" : "ghost"}
              >
                All calendars
              </ToolbarButton>
              {resources?.map((resource) => {
                const active = activeResourceIds.includes(resource.id)

                return (
                  <ToolbarButton
                    key={resource.id}
                    onClick={() => {
                      if (!onResourceFilterChange) {
                        return
                      }

                      const nextSelection = active
                        ? activeResourceIds.filter((id) => id !== resource.id)
                        : [...activeResourceIds, resource.id]

                      onResourceFilterChange(
                        nextSelection.length > 0 ? nextSelection : allResourceIds
                      )
                    }}
                    size="sm"
                    tone={active ? "secondary" : "ghost"}
                  >
                    <span
                      aria-hidden
                      className="size-2 rounded-full"
                      style={{ backgroundColor: resource.color }}
                    />
                    {resource.label}
                  </ToolbarButton>
                )
              })}
            </div>
          ) : (
            <span />
          )}
          {toolbarExtras ? (
            <div className="flex flex-wrap items-center gap-2">
              {toolbarExtras}
            </div>
          ) : null}
        </div>
      ) : null}
    </div>
  )
}

import * as React from "react"

import { isSameDay, startOfDay } from "date-fns"

import { cn } from "@/lib/utils"

import type { CalendarCreateDraft } from "../../types"
import {
  formatHourLabel,
  formatMonthDayLabel,
  formatWeekday,
  getAllDayEvents,
  getCalendarSlotClassName,
  getDayLayout,
  getEventMetaLabel,
  getNextVisibleDay,
  getWeekDays,
  isToday,
  parseTimeStringToMinuteOfDay,
  setMinuteOfDay,
  formatDurationLabel,
} from "../../utils"
import { CalendarEventCard, getResolvedAccentColor } from "./event-card"
import {
  type SharedViewProps,
  type TimeGridViewProps,
} from "../shared"
import { AllDayDropZone } from "./time-grid/all-day-drop-zone"
import { TimeGridBackground } from "./time-grid/time-grid-background"
import { TimeGridPreviewLayer } from "./time-grid/time-grid-preview-layer"
import { TimeSlotDropZone } from "./time-grid/time-slot-drop-zone"
import {
  clampGridMinute,
  formatDraftRangeLabel,
  getTimeGridHeaderId,
  getTimeGridPreviewLayout,
  getTimeGridSlotId,
} from "./time-grid/time-grid-utils"
import { useTimeGridNavigation } from "./time-grid/use-time-grid-navigation"

export const CalendarWeekView = React.memo(function CalendarWeekView(
  props: SharedViewProps & {
    minHour: number
    maxHour: number
  }
) {
  return (
    <CalendarTimeGridView
      {...props}
      days={getWeekDays(props.anchorDate, props.weekStartsOn, props.hiddenDays)}
    />
  )
})

export const CalendarDayView = React.memo(function CalendarDayView(
  props: SharedViewProps & {
    minHour: number
    maxHour: number
  }
) {
  return (
    <CalendarTimeGridView
      {...props}
      days={[startOfDay(getNextVisibleDay(props.anchorDate, props.hiddenDays))]}
    />
  )
})

function CalendarTimeGridView(props: TimeGridViewProps) {
  const [draft, setDraft] = React.useState<CalendarCreateDraft | null>(null)
  const [now, setNow] = React.useState(() => new Date())
  const scrollContainerRef = React.useRef<HTMLDivElement | null>(null)
  const minMinute = props.minHour * 60
  const maxMinute = props.maxHour * 60
  const totalMinutes = maxMinute - minMinute
  const slotCount = Math.max(1, totalMinutes / props.slotDuration)
  const gridHeight = slotCount * props.slotHeight
  const {
    dayGridRefs,
    focusDayGrid,
    focusedGridDayIndex,
    focusedSlot,
    gridInstructionsId,
    handleGridKeyDown,
    setFocusedGridDayIndex,
    setFocusedSlot,
  } = useTimeGridNavigation({
    days: props.days,
    maxMinute,
    minMinute,
    onEventCreate: props.onEventCreate,
    slotDuration: props.slotDuration,
  })
  const commitDraft = React.useEffectEvent(() => {
    if (!draft || !props.onEventCreate) {
      return
    }

    const startMinute = Math.min(draft.startMinute, draft.endMinute)
    const endMinute = Math.max(draft.startMinute, draft.endMinute)
    const start = setMinuteOfDay(startOfDay(draft.day), startMinute)
    const end = setMinuteOfDay(
      startOfDay(draft.day),
      Math.min(endMinute + props.slotDuration, 1_440)
    )

    props.onEventCreate({
      start,
      end,
    })
    setDraft(null)
  })

  React.useEffect(() => {
    if (!draft) {
      return
    }

    function handlePointerUp() {
      commitDraft()
    }

    window.addEventListener("pointerup", handlePointerUp)

    return () => {
      window.removeEventListener("pointerup", handlePointerUp)
    }
  }, [draft])

  React.useEffect(() => {
    const intervalId = window.setInterval(() => {
      setNow(new Date())
    }, 30_000)

    return () => {
      window.clearInterval(intervalId)
    }
  }, [])

  React.useEffect(() => {
    const container = scrollContainerRef.current

    if (!container || !props.scrollToTime) {
      return
    }

    const currentDate = new Date()
    const targetMinute =
      props.scrollToTime === "now"
        ? currentDate.getHours() * 60 + currentDate.getMinutes()
        : parseTimeStringToMinuteOfDay(props.scrollToTime)

    if (targetMinute === null) {
      return
    }

    const clampedMinute = Math.min(maxMinute, Math.max(minMinute, targetMinute))
    const nextScrollTop = Math.max(
      0,
      ((clampedMinute - minMinute) / props.slotDuration) * props.slotHeight -
        props.slotHeight * 2
    )

    container.scrollTop = nextScrollTop
  }, [
    maxMinute,
    minMinute,
    props.scrollToTime,
    props.slotDuration,
    props.slotHeight,
  ])

  const allDayEventsByDay = React.useMemo(() => {
    return new Map(
      props.days.map((day) => [day.getTime(), getAllDayEvents(props.occurrences, day)])
    )
  }, [props.days, props.occurrences])

  const timedLayoutsByDay = React.useMemo(() => {
    return new Map(
      props.days.map((day) => [
        day.getTime(),
        getDayLayout(props.occurrences, day, minMinute, maxMinute),
      ])
    )
  }, [maxMinute, minMinute, props.days, props.occurrences])

  return (
    <div className="min-h-0 flex-1 overflow-auto" ref={scrollContainerRef}>
      <div className="min-w-4xl">
        <div
          className="grid border-b border-border/70"
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div
            className={cn(
              "border-r border-border/70 text-[11px] tracking-[0.24em] text-muted-foreground uppercase",
              props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
            )}
          >
            Time
          </div>
          {props.days.map((day) => (
            <div
              key={`header-${day.toISOString()}`}
              className={getCalendarSlotClassName(
                props.classNames,
                "timeGridHeader",
                cn(
                  "border-r border-border/70 last:border-r-0",
                  props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
                )
              )}
              id={getTimeGridHeaderId(day)}
            >
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-[11px] tracking-[0.24em] text-muted-foreground uppercase">
                    {formatWeekday(day, {
                      locale: props.locale,
                      timeZone: props.timeZone,
                    })}
                  </p>
                  <p className="text-sm font-medium">
                    {formatMonthDayLabel(day, {
                      locale: props.locale,
                      timeZone: props.timeZone,
                    })}
                  </p>
                </div>
                {isToday(day) ? (
                  <span className="rounded-full bg-primary/12 px-2 py-1 text-[11px] font-medium text-primary">
                    Today
                  </span>
                ) : null}
              </div>
            </div>
          ))}
        </div>
        <div
          className="grid border-b border-border/70"
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div
            className={cn(
              "border-r border-border/70 text-[11px] tracking-[0.24em] text-muted-foreground uppercase",
              props.density === "compact" ? "px-3 py-2.5" : "px-3 py-3"
            )}
          >
            All day
          </div>
          {props.days.map((day) => (
            <AllDayDropZone
              key={`all-day-${day.toISOString()}`}
              activeDropTarget={props.activeDropTarget}
              classNames={props.classNames}
              day={day}
              density={props.density}
              dragPreviewOccurrence={props.dragPreviewOccurrence}
              draggingOccurrenceId={props.draggingOccurrenceId}
              events={allDayEventsByDay.get(day.getTime()) ?? []}
              getEventColor={props.getEventColor}
              hourCycle={props.hourCycle}
              interactive={props.interactive}
              locale={props.locale}
              onEventDragPointerDown={props.onEventDragPointerDown}
              onEventKeyCommand={props.onEventKeyCommand}
              onOpenContextMenu={props.onOpenContextMenu}
              onSelect={props.onSelectEvent}
              previewOccurrenceId={props.previewOccurrenceId}
              renderEvent={props.renderEvent}
              selectedEventId={props.selectedEventId}
              shouldSuppressEventClick={props.shouldSuppressEventClick}
              timeZone={props.timeZone}
            />
          ))}
        </div>
        <p className="sr-only" id={gridInstructionsId}>
          Use arrow keys to move the active time slot. Use left and right arrows
          to change days.
          {props.onEventCreate
            ? " Press Enter or Space to create an event at the active slot."
            : ""}
        </p>
        <div
          className={getCalendarSlotClassName(
            props.classNames,
            "timeGrid",
            "grid"
          )}
          style={{
            gridTemplateColumns: `4.5rem repeat(${props.days.length}, minmax(0, 1fr))`,
          }}
        >
          <div className="relative border-r border-border/70">
            {Array.from({ length: slotCount }).map((_, index) => {
              const minute = minMinute + index * props.slotDuration
              const labelDate = setMinuteOfDay(
                startOfDay(props.days[0]),
                minute
              )

              return (
                <div
                  key={`time-label-${minute}`}
                  className="border-b border-border/50 px-3 text-[11px] text-muted-foreground"
                  style={{
                    height: props.slotHeight,
                  }}
                >
                  {minute % 60 === 0 ? (
                    <div className="space-y-0.5 pt-0.5">
                      <p>
                        {formatHourLabel(labelDate, {
                          hourCycle: props.hourCycle,
                          locale: props.locale,
                          timeZone: props.timeZone,
                        })}
                      </p>
                      {props.showSecondaryTimeZone &&
                      props.secondaryTimeZone ? (
                        <p className="text-[10px] text-muted-foreground/80">
                          {formatHourLabel(labelDate, {
                            hourCycle: props.hourCycle,
                            locale: props.locale,
                            timeZone: props.secondaryTimeZone,
                          })}
                        </p>
                      ) : null}
                    </div>
                  ) : null}
                </div>
              )
            })}
          </div>
          {props.days.map((day, dayIndex) => {
            const layout = timedLayoutsByDay.get(day.getTime()) ?? []
            const previewLayout = getTimeGridPreviewLayout(
              layout,
              props.dragPreviewOccurrence,
              day,
              minMinute,
              maxMinute
            )
            const showTimedSlotDropHighlight = !previewLayout
            const currentMinuteOfDay = now.getHours() * 60 + now.getMinutes()
            const showNowIndicator =
              isSameDay(day, now) &&
              currentMinuteOfDay >= minMinute &&
              currentMinuteOfDay <= maxMinute
            const nowIndicatorTop =
              ((currentMinuteOfDay - minMinute) / totalMinutes) * gridHeight
            const headerId = getTimeGridHeaderId(day)
            const activeSlotId =
              focusedSlot.dayIndex === dayIndex
                ? getTimeGridSlotId(day, focusedSlot.minuteOfDay)
                : undefined

            return (
              <div
                key={`day-column-${day.toISOString()}`}
                className={getCalendarSlotClassName(
                  props.classNames,
                  "timeGridDayColumn",
                  "relative border-r border-border/70 last:border-r-0"
                )}
              >
                <div
                  aria-activedescendant={activeSlotId}
                  aria-colcount={1}
                  aria-describedby={gridInstructionsId}
                  aria-labelledby={headerId}
                  aria-rowcount={slotCount}
                  className="relative h-full outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-primary/35"
                  onBlur={(event) => {
                    if (
                      event.relatedTarget instanceof Node &&
                      event.currentTarget.contains(event.relatedTarget)
                    ) {
                      return
                    }

                    setFocusedGridDayIndex((currentIndex) =>
                      currentIndex === dayIndex ? null : currentIndex
                    )
                  }}
                  onFocus={() => {
                    setFocusedGridDayIndex(dayIndex)
                    setFocusedSlot((currentSlot) => ({
                      dayIndex,
                      minuteOfDay: clampGridMinute(
                        currentSlot.minuteOfDay,
                        minMinute,
                        maxMinute,
                        props.slotDuration
                      ),
                    }))
                  }}
                  onKeyDown={(event) => handleGridKeyDown(dayIndex, day, event)}
                  ref={(element) => {
                    dayGridRefs.current[dayIndex] = element
                  }}
                  role="grid"
                  style={{
                    height: gridHeight,
                  }}
                  tabIndex={focusedSlot.dayIndex === dayIndex ? 0 : -1}
                >
                  <TimeGridBackground
                    blockedRanges={props.blockedRanges}
                    businessHours={props.businessHours}
                    day={day}
                    gridHeight={gridHeight}
                    maxMinute={maxMinute}
                    minMinute={minMinute}
                    slotDuration={props.slotDuration}
                    slotHeight={props.slotHeight}
                  />
                  <div
                    className="absolute inset-0 grid"
                    style={{
                      gridTemplateRows: `repeat(${slotCount}, ${props.slotHeight}px)`,
                    }}
                  >
                    {Array.from({ length: slotCount }).map((_, index) => {
                      const minuteOfDay = minMinute + index * props.slotDuration
                      const slotStart = setMinuteOfDay(startOfDay(day), minuteOfDay)
                      const slotEnd = setMinuteOfDay(
                        startOfDay(day),
                        Math.min(minuteOfDay + props.slotDuration, 1_440)
                      )

                      return (
                        <div
                          key={`${day.toISOString()}-${minuteOfDay}`}
                          role="row"
                        >
                          <TimeSlotDropZone
                            active={
                              focusedSlot.dayIndex === dayIndex &&
                              focusedSlot.minuteOfDay === minuteOfDay
                            }
                            blocked={
                              props.blockedRanges?.some((range) =>
                                slotStart.getTime() < range.end.getTime() &&
                                slotEnd.getTime() > range.start.getTime()
                              ) ?? false
                            }
                            classNames={props.classNames}
                            day={day}
                            draft={draft}
                            focusVisible={focusedGridDayIndex === dayIndex}
                            hourCycle={props.hourCycle}
                            isDragTarget={
                              showTimedSlotDropHighlight &&
                              props.activeDropTarget?.kind === "slot" &&
                              props.activeDropTarget.day.getTime() === day.getTime() &&
                              props.activeDropTarget.minuteOfDay === minuteOfDay
                            }
                            locale={props.locale}
                            minuteOfDay={minuteOfDay}
                            onBeginCreate={() => {
                              if (!props.onEventCreate) {
                                return
                              }

                              setDraft({
                                day,
                                startMinute: minuteOfDay,
                                endMinute: minuteOfDay,
                              })
                            }}
                            onExtendCreate={() => {
                              if (!draft || !isSameDay(draft.day, day)) {
                                return
                              }

                              setDraft({
                                ...draft,
                                endMinute: minuteOfDay,
                              })
                            }}
                            onFocusCell={() => {
                              setFocusedGridDayIndex(dayIndex)
                              setFocusedSlot({
                                dayIndex,
                                minuteOfDay,
                              })
                              focusDayGrid(dayIndex)
                            }}
                            slotId={getTimeGridSlotId(day, minuteOfDay)}
                            timeZone={props.timeZone}
                          />
                        </div>
                      )
                    })}
                  </div>
                  {draft && isSameDay(draft.day, day) ? (
                    <div
                      className="pointer-events-none absolute inset-x-1 rounded-[calc(var(--radius)*0.9)] border border-dashed border-primary/60 bg-primary/10"
                      style={{
                        top:
                          ((Math.min(draft.startMinute, draft.endMinute) -
                            minMinute) /
                            props.slotDuration) *
                          props.slotHeight,
                        height:
                          ((Math.abs(draft.endMinute - draft.startMinute) +
                            props.slotDuration) /
                            props.slotDuration) *
                          props.slotHeight,
                      }}
                    >
                      {props.showCreatePreviewMeta ? (
                        <span className="absolute left-2 top-2 rounded-full bg-background/95 px-2 py-0.5 text-[10px] font-medium text-foreground shadow-xs">
                          {formatDraftRangeLabel(draft, {
                            day,
                            hourCycle: props.hourCycle,
                            locale: props.locale,
                            slotDuration: props.slotDuration,
                            timeZone: props.timeZone,
                          })}
                        </span>
                      ) : null}
                    </div>
                  ) : null}
                  {previewLayout ? (
                    <TimeGridPreviewLayer
                      column={previewLayout.column}
                      columns={previewLayout.columns}
                      height={previewLayout.height}
                      minMinute={minMinute}
                      slotDuration={props.slotDuration}
                      slotHeight={props.slotHeight}
                      top={previewLayout.top}
                    />
                  ) : null}
                  {showNowIndicator ? (
                    <div
                      className="pointer-events-none absolute inset-x-0 z-20"
                      style={{
                        top: nowIndicatorTop,
                      }}
                    >
                      <div className="relative h-0">
                        <div className="absolute top-1/2 left-0 size-2.5 -translate-x-1/2 -translate-y-1/2 rounded-full bg-primary shadow-[0_0_0_3px_var(--color-background)]" />
                        <div className="h-0.5 w-full bg-primary" />
                      </div>
                    </div>
                  ) : null}
                  {layout.map((item, index) => {
                    const width = 100 / item.columns
                    const left = item.column * width

                    return (
                      <div
                        key={item.occurrence.occurrenceId}
                        className="absolute px-1"
                        style={{
                          top:
                            ((item.top - minMinute) / props.slotDuration) *
                            props.slotHeight,
                          height: Math.max(
                            props.slotHeight - 4,
                            (item.height / props.slotDuration) * props.slotHeight
                          ),
                          left: `calc(${left}% + 0px)`,
                          width: `calc(${width}% - 0px)`,
                        }}
                      >
                        <CalendarEventCard
                          accentColor={getResolvedAccentColor(
                            item.occurrence,
                            props.getEventColor,
                            index
                          )}
                          classNames={props.classNames}
                          density={props.density}
                          dragging={
                            props.draggingOccurrenceId === item.occurrence.occurrenceId
                          }
                          event={item.occurrence}
                          interactive={props.interactive}
                          onDragPointerDown={props.onEventDragPointerDown}
                          onEventKeyCommand={props.onEventKeyCommand}
                          onResizeHandlePointerDown={
                            props.onResizeHandlePointerDown
                          }
                          onOpenContextMenu={props.onOpenContextMenu}
                          onSelect={props.onSelectEvent}
                          preview={
                            props.previewOccurrenceId ===
                            item.occurrence.occurrenceId
                          }
                          previewMetaLabel={
                            props.showDragPreviewMeta &&
                            props.previewOccurrenceId === item.occurrence.occurrenceId
                              ? formatDurationLabel(
                                  item.occurrence.start,
                                  item.occurrence.end,
                                  item.occurrence.allDay
                                )
                              : undefined
                          }
                          renderEvent={props.renderEvent}
                          selected={
                            props.selectedEventId ===
                            item.occurrence.occurrenceId
                          }
                          shouldSuppressClick={props.shouldSuppressEventClick}
                          showResizeHandles
                          timeLabel={getEventMetaLabel(item.occurrence, {
                            hourCycle: props.hourCycle,
                            locale: props.locale,
                            timeZone: props.timeZone,
                          })}
                          variant="time-grid"
                        />
                      </div>
                    )
                  })}
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

import * as React from "react"

import { cn } from "@/lib/utils"

import {
  formatDayNumber,
  formatMonthDayLabel,
  formatWeekday,
  getCalendarSlotClassName,
  getDayEvents,
  getEventMetaLabel,
  getMonthDays,
  isOutsideMonth,
  isToday,
} from "../../utils"
import {
  CalendarEventCard,
  getResolvedAccentColor,
} from "./event-card"
import { maxMonthEvents, type SharedViewProps } from "../shared"

export const CalendarMonthView = React.memo(function CalendarMonthView(
  props: SharedViewProps
) {
  const days = getMonthDays(
    props.anchorDate,
    props.weekStartsOn,
    props.hiddenDays
  )
  const columnCount = Math.max(1, 7 - props.hiddenDays.length)

  return (
    <div className="min-h-0 flex-1 overflow-auto">
      <div className="min-w-[48rem]">
        <div
          className="grid border-b border-border/70"
          role="row"
          style={{
            gridTemplateColumns: `repeat(${columnCount}, minmax(0, 1fr))`,
          }}
        >
          {days.slice(0, columnCount).map((day, index) => (
            <div
              key={`month-heading-${day.toISOString()}`}
              id={getMonthHeaderId(index)}
              className="px-3 py-2 text-xs tracking-[0.24em] text-muted-foreground uppercase"
              role="columnheader"
            >
              {formatWeekday(day, {
                locale: props.locale,
                timeZone: props.timeZone,
              })}
            </div>
          ))}
        </div>
        <div
          className={getCalendarSlotClassName(
            props.classNames,
            "monthGrid",
            "grid"
          )}
          aria-label="Month view calendar"
          role="grid"
          style={{
            gridTemplateColumns: `repeat(${columnCount}, minmax(0, 1fr))`,
          }}
        >
          {days.map((day, index) => (
            <MonthDayCell
              columnHeaderId={getMonthHeaderId(index % columnCount)}
              key={day.toISOString()}
              day={day}
              {...props}
            />
          ))}
        </div>
      </div>
    </div>
  )
})

type MonthDayCellProps = SharedViewProps & {
  columnHeaderId: string
  day: Date
}

function MonthDayCell({
  activeDropTarget,
  anchorDate,
  classNames,
  columnHeaderId,
  day,
  density,
  draggingOccurrenceId,
  getEventColor,
  interactive,
  locale,
  occurrences,
  onEventDragPointerDown,
  onEventKeyCommand,
  onOpenContextMenu,
  onSelectEvent,
  previewOccurrenceId,
  renderEvent,
  selectedEventId,
  shouldSuppressEventClick,
  timeZone,
}: MonthDayCellProps) {
  const events = getDayEvents(occurrences, day)
  const visibleEvents = events.slice(0, maxMonthEvents)
  const remainingEvents = events.length - visibleEvents.length
  const isDragTarget =
    activeDropTarget?.kind === "day" &&
    activeDropTarget.day.getTime() === day.getTime()

  return (
    <section
      aria-describedby={columnHeaderId}
      aria-label={`${formatWeekday(day, {
        locale,
        timeZone,
      })} ${formatMonthDayLabel(day, {
        locale,
        timeZone,
      })}. ${events.length} ${events.length === 1 ? "event" : "events"}.`}
      className={getCalendarSlotClassName(
        classNames,
        isOutsideMonth(day, anchorDate) ? "monthCellMuted" : "monthCell",
        cn(
          "flex flex-col border-r border-b border-border/70 px-2 py-2 transition-colors",
          density === "compact" ? "min-h-[9rem] gap-1.5" : "min-h-[10.5rem] gap-2",
          isDragTarget ? "bg-muted/50" : "",
          isOutsideMonth(day, anchorDate) ? "bg-muted/25" : "bg-background"
        )
      )}
      data-calendar-drop-target-day={day.toISOString()}
      data-calendar-drop-target-kind="day"
      role="gridcell"
    >
      <div className="flex items-center justify-between">
        <span className="text-xs tracking-[0.24em] text-muted-foreground uppercase">
          {formatWeekday(day, {
            locale,
            timeZone,
          })}
        </span>
        <span
          aria-current={isToday(day) ? "date" : undefined}
          className={cn(
            "inline-flex size-8 items-center justify-center rounded-full text-sm font-medium",
            isToday(day)
              ? "bg-primary text-primary-foreground"
              : "text-foreground"
          )}
        >
          {formatDayNumber(day, {
            locale,
            timeZone,
          })}
        </span>
      </div>
      <div className="space-y-1">
        {visibleEvents.map((occurrence, index) => (
          <CalendarEventCard
            key={occurrence.occurrenceId}
            accentColor={getResolvedAccentColor(
              occurrence,
              getEventColor,
              index
            )}
            classNames={classNames}
            density={density}
            dragging={draggingOccurrenceId === occurrence.occurrenceId}
            event={occurrence}
            interactive={interactive}
            onDragPointerDown={onEventDragPointerDown}
            onEventKeyCommand={onEventKeyCommand}
            onOpenContextMenu={onOpenContextMenu}
            onSelect={onSelectEvent}
            preview={previewOccurrenceId === occurrence.occurrenceId}
            renderEvent={renderEvent}
            selected={selectedEventId === occurrence.occurrenceId}
            shouldSuppressClick={shouldSuppressEventClick}
            timeLabel={getEventMetaLabel(occurrence, {
              locale,
              timeZone,
            })}
            variant="month"
          />
        ))}
        {remainingEvents > 0 ? (
          <p className="px-1 text-xs text-muted-foreground">
            +{remainingEvents} more
          </p>
        ) : null}
      </div>
    </section>
  )
}

function getMonthHeaderId(index: number) {
  return `calendar-month-header-${index}`
}

