type AgendaDayGroupProps = {
  activeDropTarget?: CalendarAgendaViewProps["activeDropTarget"]
  classNames?: CalendarClassNames
  day: Date
  density: "comfortable" | "compact"
  draggingOccurrenceId?: string
  events: CalendarOccurrence[]
  getEventColor?: (occurrence: CalendarOccurrence) => string
  hourCycle?: 12 | 24
  interactive: boolean
  locale?: string
  onEventDragPointerDown?: CalendarAgendaViewProps["onEventDragPointerDown"]
  onEventKeyCommand: (
    occurrence: CalendarOccurrence,
    event: React.KeyboardEvent<HTMLButtonElement>
  ) => void
  onOpenContextMenu?: (
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) => void
  onSelect: (occurrence: CalendarOccurrence) => void
  previewOccurrenceId?: string
  renderEvent?: CalendarEventRenderer
  selectedEventId?: string
  shouldSuppressEventClick?: (occurrenceId: string) => boolean
  timeZone?: string
}

function AgendaDayGroup({
  activeDropTarget,
  classNames,
  day,
  density,
  draggingOccurrenceId,
  events,
  getEventColor,
  hourCycle,
  locale,
  interactive,
  onEventDragPointerDown,
  onEventKeyCommand,
  onOpenContextMenu,
  onSelect,
  previewOccurrenceId,
  renderEvent,
  selectedEventId,
  shouldSuppressEventClick,
  timeZone,
}: AgendaDayGroupProps) {
  const headingId = `calendar-agenda-heading-${day.getTime()}`
  const isDragTarget =
    activeDropTarget?.kind === "day" &&
    activeDropTarget.day.getTime() === day.getTime()

  return (
    <section
      aria-labelledby={headingId}
      className={getCalendarSlotClassName(
        classNames,
        "agendaGroup",
        cn(
          density === "compact"
            ? "grid gap-3 px-4 py-3 md:grid-cols-[6.5rem_1fr] md:px-5"
            : "grid gap-4 px-4 py-4 md:grid-cols-[7rem_1fr] md:px-5",
          isDragTarget ? "bg-muted/50" : ""
        )
      )}
      data-calendar-drop-target-day={day.toISOString()}
      data-calendar-drop-target-kind="day"
      role="listitem"
    >
      <div className="space-y-1">
        <p className="text-[11px] tracking-[0.24em] text-muted-foreground uppercase">
          {formatAgendaEyebrow(day, {
            locale,
            timeZone,
          })}
        </p>
        <h3 className="font-medium">
          <span id={headingId}>
            {formatAgendaHeading(day, {
              locale,
              timeZone,
            })}
          </span>
        </h3>
      </div>
      <div
        className={density === "compact" ? "space-y-1.5" : "space-y-2"}
        role="list"
      >
        {events.length === 0 ? (
          <p className="py-3 text-sm text-muted-foreground">
            No events scheduled.
          </p>
        ) : (
          events.map((occurrence) => (
            <div key={occurrence.occurrenceId} role="listitem">
              <CalendarEventCard
                accentColor={getResolvedAccentColor(occurrence, getEventColor)}
                classNames={classNames}
                density={density}
                dragging={draggingOccurrenceId === occurrence.occurrenceId}
                event={occurrence}
                interactive={interactive}
                onDragPointerDown={onEventDragPointerDown}
                onEventKeyCommand={onEventKeyCommand}
                onOpenContextMenu={onOpenContextMenu}
                onSelect={onSelect}
                preview={previewOccurrenceId === occurrence.occurrenceId}
                renderEvent={renderEvent}
                selected={selectedEventId === occurrence.occurrenceId}
                shouldSuppressClick={shouldSuppressEventClick}
                timeLabel={getEventMetaLabel(occurrence, {
                  hourCycle,
                  locale,
                  timeZone,
                })}
                variant="agenda"
              />
            </div>
          ))
        )}
      </div>
    </section>
  )
}

import type {
  CSSProperties,
  KeyboardEvent,
  MouseEvent,
  PointerEvent as ReactPointerEvent,
} from "react"

import { cn } from "@/lib/utils"

import type {
  CalendarClassNames,
  CalendarDensity,
  CalendarEventRenderer,
  CalendarOccurrence,
} from "../../types"
import {
  canMoveOccurrence,
  canResizeOccurrence,
  getCalendarSlotClassName,
  getOccurrenceAccentColor,
} from "../../utils"
import type { CalendarEventMenuPosition, EventVariant } from "../shared"

type CalendarEventCardProps = {
  accentColor: string
  classNames?: CalendarClassNames
  density?: CalendarDensity
  dragging?: boolean
  event: CalendarOccurrence
  interactive: boolean
  onDragPointerDown?: (
    occurrence: CalendarOccurrence,
    variant: EventVariant,
    event: ReactPointerEvent<HTMLButtonElement>
  ) => void
  onEventKeyCommand: (
    occurrence: CalendarOccurrence,
    event: KeyboardEvent<HTMLButtonElement>
  ) => void
  onResizeHandlePointerDown?: (
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    event: ReactPointerEvent<HTMLSpanElement>
  ) => void
  onOpenContextMenu?: (
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) => void
  onSelect: (occurrence: CalendarOccurrence) => void
  preview?: boolean
  previewMetaLabel?: string
  renderEvent?: CalendarEventRenderer
  selected?: boolean
  showResizeHandles?: boolean
  shouldSuppressClick?: (occurrenceId: string) => boolean
  timeLabel: string
  variant: EventVariant
}

type EventSurfaceProps = {
  accentColor: string
  ariaLabel?: string
  className?: string
  density?: CalendarDensity
  dragging?: boolean
  event: CalendarOccurrence
  overlay?: boolean
  onDragPointerDown?: (
    occurrence: CalendarOccurrence,
    variant: EventVariant,
    event: ReactPointerEvent<HTMLButtonElement>
  ) => void
  onKeyDown?: (event: KeyboardEvent<HTMLButtonElement>) => void
  onResizeHandlePointerDown?: (
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    event: ReactPointerEvent<HTMLSpanElement>
  ) => void
  onOpenContextMenu?: (
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) => void
  onSelect?: () => void
  preview?: boolean
  previewMetaLabel?: string
  renderEvent?: CalendarEventRenderer
  selected?: boolean
  showResizeHandles?: boolean
  style?: CSSProperties
  shouldSuppressClick?: (occurrenceId: string) => boolean
  timeLabel: string
  variant: EventVariant
}

export function CalendarEventCard({
  accentColor,
  classNames,
  density = "comfortable",
  dragging = false,
  event,
  interactive,
  onDragPointerDown,
  onEventKeyCommand,
  onResizeHandlePointerDown,
  onOpenContextMenu,
  onSelect,
  preview = false,
  previewMetaLabel,
  renderEvent,
  selected,
  showResizeHandles,
  shouldSuppressClick,
  timeLabel,
  variant,
}: CalendarEventCardProps) {
  const dragEnabled = interactive && canMoveOccurrence(event) && !preview

  return (
    <div className={variant === "time-grid" ? "h-full" : undefined}>
      <EventSurface
        accentColor={accentColor}
        ariaLabel={`${event.title}. ${timeLabel}.`}
        className={getEventSlotClassName(classNames, variant)}
        density={density}
        dragging={dragging}
        event={event}
        onDragPointerDown={dragEnabled ? onDragPointerDown : undefined}
        onKeyDown={(keyEvent) => onEventKeyCommand(event, keyEvent)}
        onResizeHandlePointerDown={onResizeHandlePointerDown}
        onOpenContextMenu={onOpenContextMenu}
        onSelect={() => onSelect(event)}
        preview={preview}
        previewMetaLabel={previewMetaLabel}
        renderEvent={renderEvent}
        selected={selected}
        showResizeHandles={
          showResizeHandles &&
          interactive &&
          !preview &&
          canResizeOccurrence(event)
        }
        shouldSuppressClick={shouldSuppressClick}
        timeLabel={timeLabel}
        variant={variant}
      />
    </div>
  )
}

export function EventSurface({
  accentColor,
  ariaLabel,
  className,
  density = "comfortable",
  dragging = false,
  event,
  overlay = false,
  onDragPointerDown,
  onKeyDown,
  onResizeHandlePointerDown,
  onOpenContextMenu,
  onSelect,
  preview = false,
  previewMetaLabel,
  renderEvent,
  selected,
  showResizeHandles,
  style,
  shouldSuppressClick,
  timeLabel,
  variant,
}: EventSurfaceProps) {
  const isCompact = variant === "month" || variant === "all-day"

  function openContextMenu(position: CalendarEventMenuPosition) {
    if (!onOpenContextMenu || overlay) {
      return
    }

    onSelect?.()
    onOpenContextMenu(event, position)
  }

  function handleClick(event: MouseEvent<HTMLButtonElement>) {
    if (shouldSuppressClick?.(event.currentTarget.dataset.calendarOccurrenceId ?? "")) {
      event.preventDefault()
      event.stopPropagation()
      return
    }

    onSelect?.()
  }

  function handleContextMenu(event: MouseEvent<HTMLButtonElement>) {
    event.preventDefault()
    event.stopPropagation()
    openContextMenu({
      x: event.clientX,
      y: event.clientY,
    })
  }

  function handleKeyDown(event: KeyboardEvent<HTMLButtonElement>) {
    onKeyDown?.(event)

    if (event.defaultPrevented || !onOpenContextMenu || overlay) {
      return
    }

    if (
      event.key === "ContextMenu" ||
      (event.shiftKey && event.key === "F10")
    ) {
      const rect = event.currentTarget.getBoundingClientRect()

      event.preventDefault()
      openContextMenu({
        x: rect.left + rect.width / 2,
        y: rect.top + Math.min(rect.height, 24),
      })
    }
  }

  const content = renderEvent ? (
    renderEvent({
      occurrence: event,
      accentColor,
      timeLabel,
      isCompact,
      isDragging: dragging,
    })
  ) : (
    <div
      className={cn(
        "min-w-0 space-y-0.5",
        variant === "time-grid" ? "relative z-10" : undefined
      )}
    >
      {!isCompact ? (
        <p className="truncate text-[10px] font-medium tracking-[0.18em] text-muted-foreground uppercase">
          {timeLabel}
        </p>
      ) : null}
      <p className="truncate leading-tight font-medium text-card-foreground">
        {event.title}
      </p>
      {!isCompact && event.location ? (
        <p className="truncate text-[11px] text-muted-foreground">
          {event.location}
        </p>
      ) : null}
      {variant === "agenda" && event.calendarLabel ? (
        <p className="truncate text-[11px] text-muted-foreground">
          {event.calendarLabel}
        </p>
      ) : null}
    </div>
  )

  return (
    <div
      className={cn(
        "group/event relative w-full min-w-0",
        variant === "time-grid" ? "h-full" : undefined
      )}
      data-calendar-drag-surface="true"
      data-selected={selected ? "true" : undefined}
      style={style}
    >
      <button
        aria-label={ariaLabel}
        className={cn(
          getEventSurfaceClassName(
            density,
            variant,
            selected,
            dragging,
            overlay,
            preview
          ),
          className
        )}
        data-calendar-event-id={event.sourceEventId}
        data-calendar-occurrence-id={event.occurrenceId}
        data-calendar-variant={variant}
        data-selected={selected ? "true" : undefined}
        data-testid={`calendar-event-${event.sourceEventId}-${variant}`}
        onClick={handleClick}
        onContextMenu={handleContextMenu}
        onKeyDown={handleKeyDown}
        onPointerDown={(pointerEvent) => {
          if (overlay || !onDragPointerDown || pointerEvent.button !== 0) {
            return
          }

          onDragPointerDown(event, variant, pointerEvent)
        }}
        style={getEventSurfaceStyle()}
        type="button"
      >
        {preview ? (
          <span
            aria-hidden
            className="pointer-events-none absolute inset-0 rounded-[inherit] border border-dashed opacity-60"
            style={{ borderColor: accentColor }}
          />
        ) : null}
        <span
          aria-hidden
          className="pointer-events-none absolute top-1.5 bottom-1.5 left-1 w-0.5 rounded-full"
          style={{ backgroundColor: accentColor }}
        />
        {content}
        {(preview || overlay) && previewMetaLabel ? (
          <span className="pointer-events-none absolute right-2 bottom-1.5 rounded-full bg-background/92 px-1.5 py-0.5 text-[10px] font-medium text-foreground shadow-xs">
            {previewMetaLabel}
          </span>
        ) : null}
      </button>
      {showResizeHandles && !overlay ? (
        <>
          <ResizeHandle
            accentColor={accentColor}
            edge="start"
            event={event}
            interactive
            onPointerDown={onResizeHandlePointerDown}
          />
          <ResizeHandle
            accentColor={accentColor}
            edge="end"
            event={event}
            interactive
            onPointerDown={onResizeHandlePointerDown}
          />
        </>
      ) : null}
    </div>
  )
}

export function getResolvedAccentColor(
  occurrence: CalendarOccurrence,
  getEventColor?: (occurrence: CalendarOccurrence) => string,
  index = 0
) {
  return (
    getEventColor?.(occurrence) ?? getOccurrenceAccentColor(occurrence, index)
  )
}

function ResizeHandle({
  accentColor,
  edge,
  event,
  interactive,
  onPointerDown,
}: {
  accentColor: string
  edge: "start" | "end"
  event: CalendarOccurrence
  interactive: boolean
  onPointerDown?: (
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    event: ReactPointerEvent<HTMLSpanElement>
  ) => void
}) {
  return (
    <span
      data-calendar-event-id={event.sourceEventId}
      data-calendar-occurrence-id={event.occurrenceId}
      data-calendar-resize-handle={edge}
      data-testid={`calendar-resize-handle-${event.sourceEventId}-${edge}`}
      className={cn(
        "absolute inset-x-0 z-20 h-6 touch-none select-none",
        edge === "start"
          ? "top-0 cursor-ns-resize"
          : "bottom-0 cursor-ns-resize"
      )}
      onPointerDown={(pointerEvent) => {
        if (!interactive || pointerEvent.button !== 0) {
          return
        }

        pointerEvent.preventDefault()
        pointerEvent.stopPropagation()
        onPointerDown?.(event, edge, pointerEvent)
      }}
      style={{
        transform: edge === "start" ? "translateY(-50%)" : "translateY(50%)",
      }}
    >
      <span
        aria-hidden
        className={cn(
          "pointer-events-none absolute inset-x-1.5 top-1/2 h-px -translate-y-1/2 opacity-0 transition-opacity duration-150 group-hover/event:opacity-100 group-focus-visible/event:opacity-100",
          selectedHandleVisibilityClass(false)
        )}
        style={{
          backgroundColor: `${accentColor}55`,
        }}
      />
      <span
        aria-hidden
        className={cn(
          "pointer-events-none absolute top-1/2 left-1/2 h-1.5 w-8 -translate-x-1/2 -translate-y-1/2 rounded-full border border-background/90 opacity-0 shadow-sm transition-[opacity,transform] duration-150 group-hover/event:scale-100 group-hover/event:opacity-100 group-focus-visible/event:scale-100 group-focus-visible/event:opacity-100",
          selectedHandleVisibilityClass(false),
          "scale-95"
        )}
        style={{
          backgroundColor: `${accentColor}88`,
        }}
      />
    </span>
  )
}

function getEventSlotClassName(
  classNames: CalendarClassNames | undefined,
  variant: EventVariant
) {
  const slot =
    variant === "month"
      ? "monthEvent"
      : variant === "agenda"
        ? "agendaEvent"
        : "timeGridEvent"

  return getCalendarSlotClassName(classNames, slot)
}

function getEventSurfaceStyle(): CSSProperties {
  return {
    borderColor: "var(--color-border)",
    backgroundColor: "var(--color-card)",
    color: "var(--color-card-foreground)",
  }
}

function getEventSurfaceClassName(
  density: CalendarDensity,
  variant: EventVariant,
  selected: boolean | undefined,
  isDragging: boolean,
  overlay: boolean,
  preview: boolean
) {
  return cn(
    "relative w-full min-w-0 overflow-hidden rounded-[min(var(--radius-sm),4px)] border pr-[10px] pl-3 text-left shadow-xs transition-[border-color,box-shadow,opacity] duration-150 outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/40",
    density === "compact" ? "px-2 py-1.5" : "px-2 py-2",
    variant === "month" || variant === "all-day"
      ? density === "compact"
        ? "px-2 py-1 pl-3 text-[11px]"
        : "px-2 py-1.5 pl-3 text-xs"
      : "text-sm",
    variant === "agenda" ? "min-h-20" : "",
    variant === "time-grid" ? "h-full" : "",
    selected ? "border-ring ring-2 ring-ring/60" : "",
    preview ? "shadow-sm" : "",
    overlay
      ? "pointer-events-none shadow-sm"
      : isDragging && !preview
        ? "opacity-0"
        : "hover:border-foreground/15"
  )
}

function selectedHandleVisibilityClass(isDragging: boolean) {
  return isDragging
    ? "opacity-100"
    : "group-data-[selected=true]/event:opacity-100"
}

import * as React from "react"
import type { ElementType } from "react"

import {
  ArchiveBoxIcon,
  ClockIcon,
  CopySimpleIcon,
  MapPinIcon,
  NotePencilIcon,
  TrashIcon,
} from "@phosphor-icons/react"

import { cn } from "@/lib/utils"

import type { CalendarOccurrence } from "../../types"
import { getEventMetaLabel, getOccurrenceAccentColor } from "../../utils"

type CalendarEventContextMenuProps = {
  hourCycle?: 12 | 24
  locale?: string
  occurrence: CalendarOccurrence
  onArchive?: () => void
  onClose: () => void
  onDelete?: () => void
  onDuplicate?: () => void
  onOpenDetails?: () => void
  timeZone?: string
  x: number
  y: number
}

const FALLBACK_MENU_WIDTH = 220
const VIEWPORT_MARGIN = 16

export function CalendarEventContextMenu({
  hourCycle,
  locale,
  occurrence,
  onArchive,
  onClose,
  onDelete,
  onDuplicate,
  onOpenDetails,
  timeZone,
  x,
  y,
}: CalendarEventContextMenuProps) {
  const menuRef = React.useRef<HTMLDivElement>(null)
  const itemRefs = React.useRef<Array<HTMLButtonElement | null>>([])
  const [position, setPosition] = React.useState({ x, y })
  const accentColor = getOccurrenceAccentColor(occurrence)
  const actions = React.useMemo(
    () =>
      [
        onOpenDetails
          ? {
              icon: NotePencilIcon,
              key: "details",
              label: "Open details",
              onSelect: onOpenDetails,
            }
          : null,
        onDuplicate
          ? {
              icon: CopySimpleIcon,
              key: "duplicate",
              label: "Duplicate event",
              onSelect: onDuplicate,
            }
          : null,
        onArchive
          ? {
              icon: ArchiveBoxIcon,
              key: "archive",
              label: "Archive event",
              onSelect: onArchive,
            }
          : null,
        onDelete
          ? {
              destructive: true,
              icon: TrashIcon,
              key: "delete",
              label: "Delete event",
              onSelect: onDelete,
            }
          : null,
      ].filter((action) => action !== null),
    [onArchive, onDelete, onDuplicate, onOpenDetails]
  )

  React.useLayoutEffect(() => {
    const menuElement = menuRef.current

    if (!menuElement) {
      return
    }

    const rect = menuElement.getBoundingClientRect()

    setPosition({
      x: Math.min(
        Math.max(x, VIEWPORT_MARGIN),
        window.innerWidth -
          Math.max(rect.width, FALLBACK_MENU_WIDTH) -
          VIEWPORT_MARGIN
      ),
      y: Math.min(
        Math.max(y, VIEWPORT_MARGIN),
        window.innerHeight - rect.height - VIEWPORT_MARGIN
      ),
    })
  }, [x, y])

  React.useEffect(() => {
    function handlePointerDown(event: PointerEvent) {
      if (
        menuRef.current &&
        event.target instanceof Node &&
        !menuRef.current.contains(event.target)
      ) {
        onClose()
      }
    }

    function handleKeyDown(event: KeyboardEvent) {
      if (event.key === "Escape") {
        onClose()
      }
    }

    function handleViewportChange() {
      onClose()
    }

    window.addEventListener("pointerdown", handlePointerDown)
    window.addEventListener("keydown", handleKeyDown)
    window.addEventListener("resize", handleViewportChange)
    window.addEventListener("scroll", handleViewportChange, true)

    return () => {
      window.removeEventListener("pointerdown", handlePointerDown)
      window.removeEventListener("keydown", handleKeyDown)
      window.removeEventListener("resize", handleViewportChange)
      window.removeEventListener("scroll", handleViewportChange, true)
    }
  }, [onClose])

  React.useEffect(() => {
    itemRefs.current[0]?.focus()
  }, [actions.length])

  function handleMenuKeyDown(event: React.KeyboardEvent<HTMLDivElement>) {
    if (event.key === "ArrowDown" || event.key === "ArrowUp") {
      event.preventDefault()

      const currentIndex = itemRefs.current.findIndex(
        (item) => item === document.activeElement
      )
      const direction = event.key === "ArrowDown" ? 1 : -1
      const nextIndex =
        currentIndex === -1
          ? 0
          : (currentIndex + direction + actions.length) % actions.length

      itemRefs.current[nextIndex]?.focus()
      return
    }

    if (event.key === "Home") {
      event.preventDefault()
      itemRefs.current[0]?.focus()
      return
    }

    if (event.key === "End") {
      event.preventDefault()
      itemRefs.current[actions.length - 1]?.focus()
    }
  }

  return (
    <div
      ref={menuRef}
      aria-label={`Actions for ${occurrence.title}`}
      className="fixed z-50 w-[15rem] overflow-hidden rounded-[calc(var(--radius)*1.05)] border border-border/80 bg-popover/98 p-1 shadow-[0_18px_48px_-24px_rgba(15,23,42,0.52)] ring-1 ring-black/5 backdrop-blur-xl animate-in fade-in-0 zoom-in-95"
      data-testid="calendar-event-context-menu"
      onKeyDown={handleMenuKeyDown}
      role="menu"
      style={{
        left: position.x,
        top: position.y,
      }}
    >
      <div className="border-b border-border/70 px-2.5 py-2">
        <div className="flex items-center gap-2.5">
          <span className="inline-flex size-6 shrink-0 items-center justify-center rounded-md bg-muted/55">
            <span
              aria-hidden
              className="size-2 rounded-full"
              style={{ backgroundColor: accentColor }}
            />
          </span>
          <div className="min-w-0 flex-1">
            <p className="truncate text-[13px] font-medium text-popover-foreground">
              {occurrence.title}
            </p>
            <div className="mt-0.5 flex flex-wrap items-center gap-x-2 gap-y-0.5 text-[11px] text-muted-foreground">
              <span className="inline-flex items-center gap-1">
                <ClockIcon className="size-3" />
                {getEventMetaLabel(occurrence, {
                  hourCycle,
                  locale,
                  timeZone,
                })}
              </span>
              <span className="truncate text-[10px] tracking-[0.18em] uppercase">
                {occurrence.calendarLabel ??
                  occurrence.resourceId ??
                  "Event"}
              </span>
            </div>
            {occurrence.location ? (
              <p className="mt-0.5 truncate text-[11px] text-muted-foreground">
                <span className="inline-flex items-center gap-1">
                  <MapPinIcon className="size-3" />
                  {occurrence.location}
                </span>
              </p>
            ) : null}
          </div>
        </div>
      </div>
      <div className="py-1">
        {actions.map((action, index) => (
          <ContextActionButton
            key={action.key}
            buttonRef={(element) => {
              itemRefs.current[index] = element
            }}
            destructive={action.destructive}
            icon={action.icon}
            label={action.label}
            onClick={action.onSelect}
            testId={`calendar-event-action-${action.key}`}
          />
        ))}
      </div>
    </div>
  )
}

function ContextActionButton({
  buttonRef,
  destructive = false,
  icon: Icon,
  label,
  onClick,
  testId,
}: {
  buttonRef?: (element: HTMLButtonElement | null) => void
  destructive?: boolean
  icon: ElementType<{ className?: string }>
  label: string
  onClick: () => void
  testId: string
}) {
  return (
    <button
      className={cn(
        "group mx-1 flex w-[calc(100%-0.5rem)] items-center gap-2.5 rounded-[calc(var(--radius)*0.75)] px-2 py-1.5 text-left transition-colors outline-none focus-visible:ring-2 focus-visible:ring-ring/70",
        destructive
          ? "text-destructive hover:bg-destructive/10"
          : "text-popover-foreground hover:bg-accent/70 hover:text-accent-foreground"
      )}
      data-testid={testId}
      onClick={onClick}
      ref={buttonRef}
      role="menuitem"
      type="button"
    >
      <span
        className={cn(
          "inline-flex size-6 shrink-0 items-center justify-center rounded-md transition-colors",
          destructive
            ? "bg-destructive/10 text-destructive"
            : "bg-muted/55 text-muted-foreground group-hover:bg-accent group-hover:text-accent-foreground"
        )}
      >
        <Icon className="size-3.5" />
      </span>
      <span className="min-w-0 truncate text-[13px] font-medium">
        {label}
      </span>
    </button>
  )
}

import * as React from "react"

import { ArrowsOutCardinalIcon, ClockClockwiseIcon } from "@phosphor-icons/react"

import { Button } from "@/components/ui/button"

import type {
  CalendarEventChangeConfirmation,
  CalendarEventChangeConfirmationContext,
} from "../../types"
import { useModalFocus } from "./use-modal-focus"

type CalendarEventChangeConfirmationDialogProps = {
  config?: CalendarEventChangeConfirmation
  context: CalendarEventChangeConfirmationContext | null
  hourCycle?: 12 | 24
  locale?: string
  onCancel: () => void
  onConfirm: () => void
  timeZone?: string
}

export function CalendarEventChangeConfirmationDialog({
  config,
  context,
  hourCycle,
  locale,
  onCancel,
  onConfirm,
  timeZone,
}: CalendarEventChangeConfirmationDialogProps) {
  const dialogRef = React.useRef<HTMLDivElement | null>(null)
  const confirmButtonRef = React.useRef<HTMLButtonElement | null>(null)
  const titleId = React.useId()
  const descriptionId = React.useId()

  useModalFocus({
    containerRef: dialogRef,
    initialFocusRef: confirmButtonRef,
    onClose: onCancel,
    open: Boolean(context),
  })

  if (!context) {
    return null
  }

  const resolvedTitle = resolveConfiguredText(
    config,
    "title",
    context,
    getDefaultTitle(context)
  )
  const resolvedDescription = resolveConfiguredText(
    config,
    "description",
    context,
    getDefaultDescription(context, {
      hourCycle,
      locale,
      timeZone,
    })
  )
  const resolvedConfirmLabel = resolveConfiguredText(
    config,
    "confirmLabel",
    context,
    context.action === "move" ? "Apply change" : "Apply resize"
  )
  const resolvedCancelLabel =
    typeof config === "object" ? config.cancelLabel ?? "Cancel" : "Cancel"
  const Icon =
    context.action === "move" ? ArrowsOutCardinalIcon : ClockClockwiseIcon

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/45 px-4 py-6 backdrop-blur-sm">
