          <div className="min-w-0 flex-1">
            <h2 className="text-base font-semibold tracking-tight" id={titleId}>
              {resolvedTitle}
            </h2>
            <p
              className="mt-1 text-sm leading-6 text-muted-foreground"
              id={descriptionId}
            >
